    id: string; startMouseX: number; startMouseY: number;
    origX: number; origY: number; moved: boolean;
  } | null>(null);
  const mouseDownOnSite = useRef(false);

  const commitSites = useCallback((next: Site[]) => {
    sitesRef.current = next;
    setSitesState(next);
  }, []);

